            elif L1<=n<=L2:
                colours_lower[n][k] = c[6]
        elif 5*np.pi/4 <= phi <= 3*np.pi/2:
            if n<=L1:
                colours_lower[n][k] = c[4]
            elif L1<=n<=L2:
                colours_lower[n][k] = c[2]
        elif 3*np.pi/2 <= phi <= 2*np.pi:
